VALUES
  ('dietitian-moex-11184', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者是醛固酮（aldosterone）的生理作用？ 刺激腎臟分泌鉀離子     刺激腎素（renin）分泌 刺激血管張力素II（angiotensin II）的去活性  頻尿', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11185', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '催產素（oxytocin）的製造與釋放，依序是在下列何者？ 下視丘、腦下腺前葉  下視丘、腦下腺後葉  腦下腺前葉、腎臟  腦下腺後葉、腎臟', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11186', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列對甲狀腺素的敘述，何者正確？ 甲狀腺素主要是由色胺酸（tryptophan）所衍生    碘離子須轉換成還原態的碘後，才能被甲狀腺所利用 甲狀腺球蛋白（thyroglobulin）會與碘離子結合，製造出甲狀腺素 甲狀腺球蛋白與甲狀腺素一起被釋放到血液中，此有助於甲狀腺素的運送', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11187', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '懷孕第六個月，助孕素（progesterone）主要來自：   腎上腺   黃體（corpus luteum）  胎盤（placenta）  子宮', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11188', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關濾泡促素（FSH）與卵巢的關係之敘述，何者正確？ 濾泡促素主要作用於膜細胞（theca cells）  濾泡促素抑制濾泡顆粒細胞增殖（proliferation） 濾泡促素刺激濾泡產生動情素（estrogen）  濾泡促素受到來自膜細胞的抑制素（inhibin）調控', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11189', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者為肺泡通氣量（alveolar ventilation）的定義？ 潮氣容積（tidal volume）× 呼吸頻率（次/分鐘）  （潮氣容積＋無效腔（dead space））× 呼吸頻率 （潮氣容積－無效腔）× 呼吸頻率  （肺活量－無效腔）× 呼吸頻率', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11190', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '血紅素對氧的親合力在下列何種情況下會降低？ 組織溫度下降     組織內二氧化碳增加 pH值增加     紅血球內2,3-diphosphoglycerate量減少', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11191', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何種酵素負責活化由胰臟分泌的胰蛋白 原（trypsinogen）？ 羧基端胜 （carboxypeptidase）  腸激 （enterokinase） 胺基端胜 （aminopeptidase）  彈性蛋白 （elastase）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11192', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '為何使用菊糖來計算腎臟的清除率（renal clearance）？ 菊糖會被重吸收（reabsorption）  菊糖會被分泌（secretion） 菊糖不會被過濾（filtration）  菊糖只會被過濾而不會被重吸收及分泌', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11193', 'dietitian', 'dietitian-moex-093-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '當血中氫離子濃度高於正常值，而重碳酸鹽及二氧化碳分壓低於正常值，這是何種中毒？ 代謝性鹼中毒（metabolic alkalosis）  代謝性酸中毒（metabolic acidosis） 呼吸性酸中毒（respiratory acidosis）  呼吸性鹼中毒（respiratory alkalosis）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "c2e2b6219eaf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
